// NEW: Geo Conversion Rate Query
function geoConversionQuery(days: number, frontend: string, steps: StepDef[]): string {
  const period = periodClause(days);
  const firstStepExpr = stepFilter(steps[0]);
  const lastStepExpr = stepFilter(steps[steps.length - 1]);
  return `fetch user.events, ${period}
| filter ${frontendFilter(steps, frontend)}
| filter ${anyStepFilter(steps)}
| fieldsAdd country = geo.country.iso_code
| fieldsAdd hit_first = ${firstStepExpr}
| fieldsAdd hit_last = ${lastStepExpr}
| summarize
    has_first = countIf(hit_first == true),
    has_last = countIf(hit_last == true),
    country_any = takeFirst(country),
    by: {dt.rum.session.id, country}
| fieldsAdd reached_first = has_first > 0
| fieldsAdd reached_last = has_last > 0
| summarize
    total_sessions = count(),
    entry_sessions = countIf(reached_first == true),
    conv_sessions = countIf(reached_first == true and reached_last == true),
    by: {country}
| fieldsAdd conv_rate = if(entry_sessions > 0, toDouble(conv_sessions) / toDouble(entry_sessions) * 100.0, else: 0.0)
| sort total_sessions desc
| limit 50`;
}

function geoFunnelBounceQuery(days: number, frontend: string, steps: StepDef[]): string {
  const period = periodClause(days);
  const firstStepExpr = stepFilter(steps[0]);
  const secondStepExpr = steps.length > 1 ? stepFilter(steps[1]) : "true";
  return `fetch user.events, ${period}
| filter ${frontendFilter(steps, frontend)}
| filter ${anyStepFilter(steps)}
| fieldsAdd country = geo.country.iso_code
| fieldsAdd hit_first = ${firstStepExpr}
| fieldsAdd hit_second = ${secondStepExpr}
| summarize
    has_first = countIf(hit_first == true),
    has_second = countIf(hit_second == true),
    by: {dt.rum.session.id, country}
| fieldsAdd entered = has_first > 0
| fieldsAdd bounced = has_first > 0 AND has_second == 0
| summarize
    entry_sessions = countIf(entered == true),
    bounce_sessions = countIf(bounced == true),
    by: {country}
| fieldsAdd funnel_bounce_rate = if(entry_sessions > 0, toDouble(bounce_sessions) / toDouble(entry_sessions) * 100.0, else: 0.0)
| sort entry_sessions desc
| limit 50`;
}

// NEW: Hourly Map Timelapse Query
function mapTimelapseQuery(days: number, frontend: string, steps: StepDef[], bucket: TlBucket = "1h"): string {
  const period = periodClause(days);
  const bucketExpr = bucket === "1h"
    ? `| fieldsAdd hour_bucket = formatTimestamp(start_time, format: "yyyy-MM-dd HH:00")`
    : `| fieldsAdd bucket_ts = bin(start_time, ${bucket})\n| fieldsAdd hour_bucket = formatTimestamp(bucket_ts, format: "yyyy-MM-dd HH:mm")`;
  const limit = bucket === "1h" ? 5000 : bucket === "30m" ? 8000 : 10000;
  return `fetch user.events, ${period}
| filter ${frontendFilter(steps, frontend)}
| filter ${anyStepFilter(steps)}
| fieldsAdd dur_ms = toDouble(duration) / 1000000.0
| fieldsAdd satisfaction = coalesce(if(dur_ms <= ${APDEX_T}.0, "satisfied"), if(dur_ms <= ${APDEX_4T}.0, "tolerating"), "frustrated")
| fieldsAdd country = geo.country.iso_code
| fieldsAdd lcp_ms = toDouble(web_vitals.largest_contentful_paint) / 1000000.0
| fieldsAdd cls_val = toDouble(web_vitals.cumulative_layout_shift)
| fieldsAdd inp_ms = toDouble(web_vitals.interaction_to_next_paint) / 1000000.0
${bucketExpr}
| summarize
    actions = count(),
    sessions = countDistinct(dt.rum.session.id),
    avg_dur = avg(dur_ms),
    satisfied = countIf(satisfaction == "satisfied"),
    tolerating = countIf(satisfaction == "tolerating"),
    frustrated = countIf(satisfaction == "frustrated"),
    errors = countIf(characteristics.has_error == true),
    lcp_avg = avg(lcp_ms),
    cls_avg = avg(cls_val),
    inp_avg = avg(inp_ms),
    by: {country, hour_bucket}
| sort hour_bucket asc
| limit ${limit}`;
}

